// Parse CSV results from TP53 pipeline and format for RAG API
const accession = $('Trigger: New Accession Input').item.json.accession || 'NM_000546';

// In production, parse actual CSV files from pipeline
// This demonstrates the data structure expected by the RAG API
const pipelineData = {
  accession: accession,
  sequence_length: 2591,
  gc_content: 52.8,
  mutations: [
    // Populated from mutations.csv
    { position: 524, original: 'G', mutant: 'A', amino_acid_change: 'R175H' }
  ],
  orfs: [
    // Populated from orfs.csv
    { frame: '+1', start: 203, end: 1384, length: 1181 }
  ],
  protein_domains: [
    // Populated from protein_domains.csv
    { database: 'Pfam', name: 'P53', accession: 'PF00870', start: 94, end: 292 }
  ],
  phylo_species: [
    'Homo sapiens', 'Pan troglodytes', 'Mus musculus',
    'Rattus norvegicus', 'Danio rerio'
  ]
};

return { json: { pipeline_data: pipelineData } };

const results = $json.results;
const accession = $json.accession;

const report = `
# TP53 Analysis Report
Accession: ${accession}
Generated: ${new Date().toISOString()}

## Mutation Analysis
${results.mutation_analysis?.answer || 'Not available'}

## Clinical Interpretation
${results.clinical_interpretation?.answer || 'Not available'}

## Comprehensive Report
${results.report_generation?.answer || 'Not available'}
`;

return { json: { report, accession, full_results: results } };
